                         hL1, tempVec, tempMat, true);

            uint32_t outOffset = t * totalHSize;
            AscendC::DataCopy(outputGm_[outOffset], hL1, totalHSize);
        }

        AscendC::DataCopy(h_nGm_[0], hL0, totalHSize);
        AscendC::DataCopy(h_nGm_[totalHSize], hL1, totalHSize);
    }

